#[test]
fn test_paragraph_with_inline_formatting() {
    // Paragraph with bold, italic, and a link
    let html = r#"<p>This has <strong>bold</strong>, <em>italic</em>, and a <a href="https://example.com">link</a>.</p>"#;
    let options = None;
    let result = convert(&html, options).expect("should succeed");
    let content = result.content.as_deref().unwrap_or("");
    assert!(format!("{:?}", content).contains(r#"**bold**"#), "expected to contain: {}", r#"**bold**"#);
    assert!(format!("{:?}", content).contains(r#"*italic*"#), "expected to contain: {}", r#"*italic*"#);
    assert!(format!("{:?}", content).contains(r#"[link](https://example.com)"#), "expected to contain: {}", r#"[link](https://example.com)"#);
}

