#[test]
fn test_semantic_sub_superscript() {
    // Subscript and superscript elements are preserved in output
    let html = r#"<p>H<sub>2</sub>O and E=mc<sup>2</sup></p>"#;
    let options = None;
    let result = convert(&html, options).expect("should succeed");
    let content = result.content.as_deref().unwrap_or("");
    assert!(!content.is_empty(), "expected non-empty value");
    assert!(format!("{:?}", content).contains(r#"H"#), "expected to contain: {}", r#"H"#);
    assert!(format!("{:?}", content).contains(r#"2"#), "expected to contain: {}", r#"2"#);
    assert!(format!("{:?}", content).contains(r#"O"#), "expected to contain: {}", r#"O"#);
    assert!(format!("{:?}", content).contains(r#"E=mc"#), "expected to contain: {}", r#"E=mc"#);
}

#[test]
fn test_simple_table() {
    // Simple table with header
    let html = r#"<table><thead><tr><th>Name</th><th>Age</th></tr></thead><tbody><tr><td>Alice</td><td>30</td></tr></tbody></table>"#;
    let options = None;
    let result = convert(&html, options).expect("should succeed");
    let content = result.content.as_deref().unwrap_or("");
    assert!(format!("{:?}", content).contains(r#"Name"#), "expected to contain: {}", r#"Name"#);
    assert!(format!("{:?}", content).contains(r#"Age"#), "expected to contain: {}", r#"Age"#);
    assert!(format!("{:?}", content).contains(r#"Alice"#), "expected to contain: {}", r#"Alice"#);
    assert!(format!("{:?}", content).contains(r#"30"#), "expected to contain: {}", r#"30"#);
    assert!(format!("{:?}", content).contains(r#"|"#), "expected to contain: {}", r#"|"#);
    assert!(format!("{:?}", content).contains(r#"---"#), "expected to contain: {}", r#"---"#);
}

