#[test]
fn test_table_no_thead() {
    // Table without thead uses first row as implied header
    let html = r#"<table><tr><td>Product</td><td>Price</td></tr><tr><td>Apple</td><td>1.00</td></tr></table>"#;
    let options = None;
    let result = convert(&html, options).expect("should succeed");
    let content = result.content.as_deref().unwrap_or("");
    assert!(!content.is_empty(), "expected non-empty value");
    assert!(format!("{:?}", content).contains(r#"Product"#), "expected to contain: {}", r#"Product"#);
    assert!(format!("{:?}", content).contains(r#"Price"#), "expected to contain: {}", r#"Price"#);
    assert!(format!("{:?}", content).contains(r#"Apple"#), "expected to contain: {}", r#"Apple"#);
    assert!(format!("{:?}", content).contains(r#"1.00"#), "expected to contain: {}", r#"1.00"#);
    assert!(format!("{:?}", content).contains(r#"|"#), "expected to contain: {}", r#"|"#);
}

#[test]
